// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "./LakomiToken.sol";

/**
 * @title LakomiGovern
 * @author Lakomi Protocol
 * @notice Democratic governance engine for the Lakomi cooperative (koperasi)
 * @dev UU 25/1992 compliant: 1-member-1-vote (Pasal 22), Rapat Anggota (Pasal 26-27), Pengawas (Pasal 38)
 */
contract LakomiGovern is AccessControl, ReentrancyGuard, Pausable {

    // ============================================================
    //                        ENUMS
    // ============================================================

    enum ProposalType { SPEND, PARAMETER, MEMBERSHIP, RAT_ANNUAL, CUSTOM }
    enum ProposalState { Pending, Active, Canceled, Defeated, Succeeded, Queued, Expired, Executed, Vetoed }
    enum Vote { Against, For, Abstain }

    // ============================================================
    //                    PENGAWAS (UU 25/1992 Pasal 38)
    // ============================================================

    bytes32 public constant PENGAWAS_ROLE = keccak256("PENGAWAS_ROLE");

    // ============================================================
    //                      STATE VARIABLES
    // ============================================================

    LakomiToken public immutable token;
    uint256 public votingPeriod;
    uint256 public quorumNumerator;
    uint256 public constant QUORUM_DENOMINATOR = 100;
    uint256 public executionTimelock;

    uint256 public proposalCount;

    mapping(uint256 => address) public proposalProposer;
    mapping(uint256 => string) public proposalDescription;
    mapping(uint256 => ProposalType) public proposalType;
    mapping(uint256 => address) public proposalTarget;
    mapping(uint256 => uint256) public proposalValue;
    mapping(uint256 => bytes) public proposalCallData;
    mapping(uint256 => uint256) public proposalForVotes;
    mapping(uint256 => uint256) public proposalAgainstVotes;
    mapping(uint256 => uint256) public proposalAbstainVotes;
    mapping(uint256 => uint256) public proposalStartTime;
    mapping(uint256 => uint256) public proposalEndTime;
    mapping(uint256 => uint256) public proposalQueuedTime;
    mapping(uint256 => bool) public proposalExecuted;
    mapping(uint256 => bool) public proposalCanceled;
    mapping(uint256 => bool) public proposalVetoed;

    mapping(uint256 => mapping(address => bool)) public hasVoted;
    mapping(uint256 => mapping(address => Vote)) public voteChoice;

    uint256 public ratPeriod;
    uint256 public lastRATTime;
    address public vaultAddress;

    // ============================================================
    //                        EVENTS
    // ============================================================

    event ProposalCreated(uint256 indexed id, address indexed proposer, string description, uint256 startTime, uint256 endTime);
    event VoteCast(uint256 indexed proposalId, address indexed voter, Vote support);
    event ProposalQueued(uint256 indexed id, uint256 eta);
    event ProposalExecuted(uint256 indexed id);
    event ProposalCanceled(uint256 indexed id);
    event ProposalVetoed(uint256 indexed id, address indexed pengawas);
    event RATScheduled(uint256 indexed proposalId, uint256 scheduledTime);

    // ============================================================
    //                        ERRORS
    // ============================================================

    error LakomiGovern__ZeroAddress();
    error LakomiGovern__EmptyDescription();
    error LakomiGovern__NotRegisteredMember();
    error LakomiGovern__ProposalNotActive();
    error LakomiGovern__AlreadyVoted();
    error LakomiGovern__ProposalNotSucceeded();
    error LakomiGovern__TimelockNotMet();
    error LakomiGovern__ExecutionFailed();
    error LakomiGovern__AlreadyExecuted();
    error LakomiGovern__NotProposer();
    error LakomiGovern__ProposalVetoed();
    error LakomiGovern__NotPengawas();
    error LakomiGovern__RATNotDue();

    // ============================================================
    //                      CONSTRUCTOR
    // ============================================================

    constructor(
        address _token,
        uint256 _votingPeriod,
        uint256 _quorumNumerator,
        uint256 _executionTimelock
    ) {
        if (_token == address(0)) revert LakomiGovern__ZeroAddress();

        token = LakomiToken(_token);
        votingPeriod = _votingPeriod;
        quorumNumerator = _quorumNumerator;
        executionTimelock = _executionTimelock;
        ratPeriod = 365 days;

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(PENGAWAS_ROLE, msg.sender);
    }

    // ============================================================
    //                    CORE FUNCTIONS
    // ============================================================

    function createProposal(
        string calldata description,
        ProposalType _proposalType,
        address target,
        uint256 value,
        bytes calldata callData
    ) external nonReentrant returns (uint256) {
        if (bytes(description).length == 0) revert LakomiGovern__EmptyDescription();
        if (!token.isRegisteredMember(msg.sender))
            revert LakomiGovern__NotRegisteredMember();

        uint256 _proposalId = proposalCount++;
        uint256 _startTime = block.timestamp;
        uint256 _endTime = _startTime + votingPeriod;

        proposalProposer[_proposalId] = msg.sender;
        proposalDescription[_proposalId] = description;
        proposalType[_proposalId] = _proposalType;
        proposalTarget[_proposalId] = target;
        proposalValue[_proposalId] = value;
        proposalCallData[_proposalId] = callData;
        proposalStartTime[_proposalId] = _startTime;
        proposalEndTime[_proposalId] = _endTime;

        emit ProposalCreated(_proposalId, msg.sender, description, _startTime, _endTime);
        return _proposalId;
    }

    function castVote(uint256 proposalId, Vote support) external nonReentrant {
        _castVote(proposalId, support);
    }

    function castVoteWithReason(
        uint256 proposalId,
        Vote support,
        string calldata /* reason */
    ) external nonReentrant {
        _castVote(proposalId, support);
    }

    function _castVote(uint256 proposalId, Vote support) internal {
        if (state(proposalId) != ProposalState.Active) revert LakomiGovern__ProposalNotActive();
        if (hasVoted[proposalId][msg.sender]) revert LakomiGovern__AlreadyVoted();
        if (!token.isRegisteredMember(msg.sender))
            revert LakomiGovern__NotRegisteredMember();

        hasVoted[proposalId][msg.sender] = true;
        voteChoice[proposalId][msg.sender] = support;

        // 1 member = 1 vote
        if (support == Vote.For) {
            proposalForVotes[proposalId] += 1;
        } else if (support == Vote.Against) {
            proposalAgainstVotes[proposalId] += 1;
        } else {
            proposalAbstainVotes[proposalId] += 1;
        }

        emit VoteCast(proposalId, msg.sender, support);
    }

    function queue(uint256 proposalId) external nonReentrant {
        if (state(proposalId) != ProposalState.Succeeded) revert LakomiGovern__ProposalNotSucceeded();

        proposalQueuedTime[proposalId] = block.timestamp;
        emit ProposalQueued(proposalId, block.timestamp + executionTimelock);
    }

    function execute(uint256 proposalId) external nonReentrant {
        if (proposalQueuedTime[proposalId] == 0) revert LakomiGovern__ProposalNotSucceeded();
        if (block.timestamp < proposalQueuedTime[proposalId] + executionTimelock)
            revert LakomiGovern__TimelockNotMet();
        if (proposalExecuted[proposalId]) revert LakomiGovern__AlreadyExecuted();

        proposalExecuted[proposalId] = true;

        (bool success, ) = proposalTarget[proposalId].call{value: proposalValue[proposalId]}(proposalCallData[proposalId]);
        if (!success) revert LakomiGovern__ExecutionFailed();

        emit ProposalExecuted(proposalId);
    }

    function cancel(uint256 proposalId) external {
        if (proposalProposer[proposalId] != msg.sender && !hasRole(DEFAULT_ADMIN_ROLE, msg.sender))
            revert LakomiGovern__NotProposer();
        if (proposalExecuted[proposalId]) revert LakomiGovern__AlreadyExecuted();

        proposalCanceled[proposalId] = true;
        emit ProposalCanceled(proposalId);
    }

    // ============================================================
    //           PENGAWAS VETO (UU 25/1992 Pasal 38)
    // ============================================================

    /**
     * @notice Pengawas can veto a proposal before execution
     * @dev Implements UU 25/1992 Pasal 38 — pengawas supervises kebijaksanaan pengurus
     */
    function vetoProposal(uint256 proposalId) external onlyRole(PENGAWAS_ROLE) {
        if (proposalExecuted[proposalId]) revert LakomiGovern__AlreadyExecuted();
        if (proposalCanceled[proposalId]) revert LakomiGovern__AlreadyExecuted();

        proposalVetoed[proposalId] = true;
        emit ProposalVetoed(proposalId, msg.sender);
    }

    /**
     * @notice Pengawas can trigger emergency pause on governance
     */
    function pengawasPause() external onlyRole(PENGAWAS_ROLE) {
        _pause();
    }

    // ============================================================
    //         RAT ANNUAL (UU 25/1992 Pasal 26-27)
    // ============================================================

    /**
     * @notice Creates the annual Rapat Anggota Tahunan (RAT) proposal
     * @dev UU 25/1992 Pasal 27 — RAT decides SHU, financial reports, elections
     *      Can be called by any member once per year
     */
    function scheduleAnnualRAT(string calldata description) external nonReentrant returns (uint256) {
        if (!token.isRegisteredMember(msg.sender))
            revert LakomiGovern__NotRegisteredMember();

        if (lastRATTime > 0 && block.timestamp < lastRATTime + ratPeriod) {
            revert LakomiGovern__RATNotDue();
        }

        uint256 _proposalId = proposalCount++;
        uint256 _startTime = block.timestamp;
        uint256 _endTime = _startTime + votingPeriod;

        proposalProposer[_proposalId] = msg.sender;
        proposalDescription[_proposalId] = description;
        proposalType[_proposalId] = ProposalType.RAT_ANNUAL;
        proposalTarget[_proposalId] = address(0);
        proposalValue[_proposalId] = 0;
        proposalCallData[_proposalId] = "";
        proposalStartTime[_proposalId] = _startTime;
        proposalEndTime[_proposalId] = _endTime;

        lastRATTime = block.timestamp;

        emit ProposalCreated(_proposalId, msg.sender, description, _startTime, _endTime);
        emit RATScheduled(_proposalId, block.timestamp);
        return _proposalId;
    }

    /**
     * @notice Check if RAT is due
     */
    function isRATDue() external view returns (bool) {
        if (lastRATTime == 0) return true;
        return block.timestamp >= lastRATTime + ratPeriod;
    }

    /**
     * @notice Get time until next RAT
     */
    function timeUntilNextRAT() external view returns (uint256) {
        if (lastRATTime == 0) return 0;
        uint256 next = lastRATTime + ratPeriod;
        if (block.timestamp >= next) return 0;
        return next - block.timestamp;
    }

    // ============================================================
    //                    VIEW FUNCTIONS
    // ============================================================

    function state(uint256 proposalId) public view returns (ProposalState) {
        if (proposalCanceled[proposalId]) return ProposalState.Canceled;
        if (proposalVetoed[proposalId]) return ProposalState.Vetoed;
        if (proposalExecuted[proposalId]) return ProposalState.Executed;
        if (block.timestamp < proposalStartTime[proposalId]) return ProposalState.Pending;
        if (block.timestamp < proposalEndTime[proposalId]) return ProposalState.Active;

        // Quorum check: total votes must reach quorum percentage of member count
        uint256 totalVotes = proposalForVotes[proposalId] + proposalAgainstVotes[proposalId] + proposalAbstainVotes[proposalId];
        uint256 quorumRequired = quorum();
        if (totalVotes < quorumRequired) return ProposalState.Defeated;
        if (proposalForVotes[proposalId] <= proposalAgainstVotes[proposalId]) return ProposalState.Defeated;

        if (proposalQueuedTime[proposalId] == 0) return ProposalState.Succeeded;
        if (block.timestamp > proposalQueuedTime[proposalId] + executionTimelock + 14 days) return ProposalState.Expired;

        return ProposalState.Queued;
    }

    /// @notice Quorum based on registered member count, not token supply
    function quorum() public view returns (uint256) {
        uint256 members = token.getMemberCount();
        return (members * quorumNumerator) / QUORUM_DENOMINATOR;
    }

    // ============================================================
    //                    ADMIN FUNCTIONS
    // ============================================================

    function setVotingPeriod(uint256 newPeriod) external onlyRole(DEFAULT_ADMIN_ROLE) {
        votingPeriod = newPeriod;
    }

    function setQuorumNumerator(uint256 newQuorum) external onlyRole(DEFAULT_ADMIN_ROLE) {
        quorumNumerator = newQuorum;
    }

    function setExecutionTimelock(uint256 newTimelock) external onlyRole(DEFAULT_ADMIN_ROLE) {
        executionTimelock = newTimelock;
    }

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }
}

contracts/LakomiLoans.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "./LakomiToken.sol";
import "./LakomiVault.sol";

/**
 * @title LakomiLoans
 * @author Lakomi Protocol
 * @notice Emergency loan system for Lakomi members
 * @dev Handles loan requests, approvals, disbursements, and repayments
 *
 * Key Features:
 * - Tiered LTV: 30% (Tier 1), 50% (Tier 2), 70% (Tier 3) based on contribution
 * - 5% APY interest rate
 * - 25% collateral in LAK tokens
 * - Auto-approval under threshold
 * - Partial repayments allowed
 */
contract LakomiLoans is AccessControl, ReentrancyGuard, Pausable {

    using SafeERC20 for IERC20;

    // ============================================================
    //                        ENUMS
    // ============================================================

    enum LoanStatus {
        Pending,    // Awaiting approval
        Approved,   // Approved, awaiting disbursement
        Active,     // Disbursed, awaiting repayment
        Repaid,     // Fully repaid
        Defaulted,  // Deadline missed
        Canceled    // Canceled
    }

    // ============================================================
    //                      STRUCTS
    // ============================================================

    struct Loan {
        uint256 id;
        address borrower;
        uint256 principal;         // Amount borrowed
        uint256 interest;          // Interest owed
        uint256 collateralTokens;  // LAK tokens locked
        uint256 startTime;
        uint256 dueTime;
        uint256 repaidAmount;      // Amount repaid so far
        LoanStatus status;
        string reason;
    }

    // ============================================================
    //                      STATE VARIABLES
    // ============================================================

    /// @dev LakomiToken reference
    LakomiToken public immutable token;

    /// @dev LakomiVault reference
    LakomiVault public immutable vault;

    /// @dev Interest rate in basis points (500 = 5%)
    uint256 public interestRate;

    /// @dev Max loan-to-contribution ratio — now determined per-tier
    uint256 public maxLTV;

    /// @dev Collateral requirement (2500 = 25% of loan)
    uint256 public collateralRatio;

    /// @dev Auto-approval threshold
    uint256 public autoApproveThreshold;

    /// @dev Tiered LTV values in basis points
    uint256 public constant TIER1_LTV = 3000; // 30%
    uint256 public constant TIER2_LTV = 5000; // 50%
    uint256 public constant TIER3_LTV = 7000; // 70%

    /// @dev Default loan duration in seconds
    uint256 public defaultLoanDuration;

    /// @dev Grace period after default (seconds)
    uint256 public gracePeriod;

    /// @dev All loans
    mapping(uint256 => Loan) public loans;

    /// @dev Loan count
    uint256 public loanCount;

    /// @dev Active loan count
    uint256 public activeLoanCount;

    /// @dev Borrower's loan IDs
    mapping(address => uint256[]) public borrowerLoans;

    /// @dev Total borrowed by address
    mapping(address => uint256) public totalBorrowed;

    /// @dev Role for loan approval
    bytes32 public constant APPROVER_ROLE = keccak256("APPROVER_ROLE");

    // ============================================================
    //                        EVENTS
    // ============================================================

    event LoanRequested(
        uint256 indexed id,
        address indexed borrower,
        uint256 amount,
        uint256 duration,
        string reason
    );

    event LoanApproved(uint256 indexed id, uint256 collateralRequired);
    event LoanDisbursed(uint256 indexed id, address indexed borrower, uint256 amount);
    event LoanRepaid(
        uint256 indexed id,
        address indexed borrower,
        uint256 amount,
        uint256 remaining
    );
    event LoanDefaulted(uint256 indexed id, address indexed borrower);
    event CollateralClaimed(
        uint256 indexed id,
        address indexed borrower,
        uint256 collateralAmount
    );
    event InterestRateUpdated(uint256 oldRate, uint256 newRate);
    event MaxLTVUpdated(uint256 oldLTV, uint256 newLTV);
    event CollateralRatioUpdated(uint256 oldRatio, uint256 newRatio);
    event ThresholdUpdated(uint256 oldThreshold, uint256 newThreshold);

    // ============================================================
    //                        ERRORS
    // ============================================================

    error LakomiLoans__ZeroAddress();
    error LakomiLoans__ZeroAmount();
    error LakomiLoans__InvalidDuration();
    error LakomiLoans__ExceedsMaxLoan();
    error LakomiLoans__InsufficientContribution();
    error LakomiLoans__InsufficientCollateral();
    error LakomiLoans__LoanNotFound();
    error LakomiLoans__LoanNotPending();
    error LakomiLoans__LoanNotApproved();
    error LakomiLoans__LoanNotActive();
    error LakomiLoans__AlreadyRepaid();
    error LakomiLoans__Overpayment();
    error LakomiLoans__NotDefaulted();
    error LakomiLoans__GracePeriodActive();
    error LakomiLoans__TransferFailed();

    // ============================================================
    //                      CONSTRUCTOR
    // ============================================================

    /**
     * @dev Initialize with token and vault references
     * @param _token LakomiToken address
     * @param _vault LakomiVault address
     */
    constructor(
        address _token,
        address _vault
    ) {
        if (_token == address(0) || _vault == address(0))
            revert LakomiLoans__ZeroAddress();

        token = LakomiToken(_token);
        vault = LakomiVault(_vault);

        // Default values
        interestRate = 500;              // 5% APY
        maxLTV = 5000;                   // 50%
        collateralRatio = 2500;          // 25%
        autoApproveThreshold = 200 * 10**6; // 200 USDC
        defaultLoanDuration = 30 days;
        gracePeriod = 7 days;

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(APPROVER_ROLE, msg.sender);
    }

    // ============================================================
    //                    CORE FUNCTIONS
    // ============================================================

    /**
     * @notice Requests a new loan
     * @param amount The loan amount
     * @param duration The loan duration in seconds
     * @param reason The reason for the loan
     * @return loanId The ID of the created loan
     */
    function requestLoan(
        uint256 amount,
        uint256 duration,
        string calldata reason
    ) external whenNotPaused nonReentrant returns (uint256 loanId) {
        if (amount == 0) revert LakomiLoans__ZeroAmount();
        if (duration == 0 || duration > 365 days)
            revert LakomiLoans__InvalidDuration();

        // Check contribution
        uint256 contribution = vault.getMemberBalance(msg.sender);
        uint256 borrowerMaxLTV = _calculateMaxLTV(msg.sender);
        uint256 maxLoan = (contribution * borrowerMaxLTV) / 10000;

        if (amount > maxLoan) revert LakomiLoans__ExceedsMaxLoan();
        if (contribution == 0) revert LakomiLoans__InsufficientContribution();

        // Calculate collateral needed
        uint256 collateralNeeded = (amount * collateralRatio) / 10000;
        // Convert USDC amount to LAK token amount (assuming 1:1 for simplicity)
        // In production, you'd use a price oracle
        uint256 collateralInTokens = collateralNeeded * 10**12; // USDC 6 decimals -> LAK 18 decimals

        uint256 availableTokens = token.getAvailableBalance(msg.sender);
        if (availableTokens < collateralInTokens)
            revert LakomiLoans__InsufficientCollateral();

        // Calculate interest
        uint256 interest = calculateInterest(amount, duration);

        loanId = loanCount++;

        loans[loanId] = Loan({
            id: loanId,
            borrower: msg.sender,
            principal: amount,
            interest: interest,
            collateralTokens: collateralInTokens,
            startTime: 0,
            dueTime: 0,
            repaidAmount: 0,
            status: LoanStatus.Pending,
            reason: reason
        });

        borrowerLoans[msg.sender].push(loanId);

        emit LoanRequested(loanId, msg.sender, amount, duration, reason);

        // Auto-approve if under threshold
        if (amount <= autoApproveThreshold) {
            _approveLoan(loanId);
        }
    }

    /**
     * @notice Approves a pending loan
     * @param loanId The ID of the loan
     */
    function approveLoan(uint256 loanId)
        external
        onlyRole(APPROVER_ROLE)
        nonReentrant
    {
        _approveLoan(loanId);
    }

    function _approveLoan(uint256 loanId) internal {
        Loan storage loan = loans[loanId];

        if (loan.borrower == address(0)) revert LakomiLoans__LoanNotFound();
        if (loan.status != LoanStatus.Pending) revert LakomiLoans__LoanNotPending();

        loan.status = LoanStatus.Approved;

        emit LoanApproved(loanId, loan.collateralTokens);
    }

    /**
     * @notice Disburses an approved loan
     * @param loanId The ID of the loan
     */
    function disburse(uint256 loanId) external whenNotPaused nonReentrant {
        Loan storage loan = loans[loanId];

        if (loan.borrower == address(0)) revert LakomiLoans__LoanNotFound();
        if (loan.status != LoanStatus.Approved) revert LakomiLoans__LoanNotApproved();

        token.lockTokens(loan.borrower, loan.collateralTokens);

        loan.status = LoanStatus.Active;
        loan.startTime = block.timestamp;
        loan.dueTime = block.timestamp + defaultLoanDuration;

        activeLoanCount++;
        totalBorrowed[loan.borrower] += loan.principal;

        IERC20 stableToken = IERC20(address(vault.stableToken()));
        stableToken.safeTransferFrom(address(vault), loan.borrower, loan.principal);

        emit LoanDisbursed(loanId, loan.borrower, loan.principal);
    }

    /**
     * @notice Repays part or all of a loan
     * @param loanId The ID of the loan
     * @param amount The amount to repay
     */
    function repay(uint256 loanId, uint256 amount)
        public
        whenNotPaused
        nonReentrant
    {
        Loan storage loan = loans[loanId];

        if (loan.borrower == address(0)) revert LakomiLoans__LoanNotFound();
        if (loan.status != LoanStatus.Active) revert LakomiLoans__LoanNotActive();

        uint256 totalOwed = loan.principal + loan.interest;
        uint256 remaining = totalOwed - loan.repaidAmount;

        if (remaining == 0) revert LakomiLoans__AlreadyRepaid();
        if (amount > remaining) revert LakomiLoans__Overpayment();

        IERC20 stableToken = IERC20(address(vault.stableToken()));
        stableToken.safeTransferFrom(msg.sender, address(this), amount);

        uint256 interestPortion = 0;
        if (loan.interest > 0 && totalOwed > 0) {
            uint256 interestRatio = (loan.interest * 1e18) / totalOwed;
            interestPortion = (amount * interestRatio) / 1e18;
        }

        if (interestPortion > 0) {
            stableToken.safeTransfer(address(vault), interestPortion);
            try vault.receiveRevenue(interestPortion) {} catch {}
        }

        uint256 principalPortion = amount - interestPortion;
        if (principalPortion > 0) {
            stableToken.safeTransfer(address(vault), principalPortion);
        }

        loan.repaidAmount += amount;

        if (loan.repaidAmount >= totalOwed) {
            loan.status = LoanStatus.Repaid;
            activeLoanCount--;

            token.unlockTokens(loan.borrower, loan.collateralTokens);
        }

        emit LoanRepaid(loanId, loan.borrower, amount, totalOwed - loan.repaidAmount);
    }

    /**
     * @notice Repays loan in full
     * @param loanId The ID of the loan
     */
    function repayInFull(uint256 loanId) external {
        Loan storage loan = loans[loanId];
        uint256 totalOwed = loan.principal + loan.interest;
        uint256 remaining = totalOwed - loan.repaidAmount;

        repay(loanId, remaining);
    }

    /**
     * @notice Marks a loan as defaulted
     * @param loanId The ID of the loan
     */
    function markDefaulted(uint256 loanId) external nonReentrant {
        Loan storage loan = loans[loanId];

        if (loan.borrower == address(0)) revert LakomiLoans__LoanNotFound();
        if (loan.status != LoanStatus.Active) revert LakomiLoans__LoanNotActive();

        if (block.timestamp < loan.dueTime + gracePeriod)
            revert LakomiLoans__GracePeriodActive();

        loan.status = LoanStatus.Defaulted;
        activeLoanCount--;

        emit LoanDefaulted(loanId, loan.borrower);
    }

    /**
     * @notice Claims collateral from a defaulted loan
     * @param loanId The ID of the loan
     */
    function claimCollateral(uint256 loanId) external nonReentrant {
        Loan storage loan = loans[loanId];

        if (loan.borrower == address(0)) revert LakomiLoans__LoanNotFound();
        if (loan.status != LoanStatus.Defaulted) revert LakomiLoans__NotDefaulted();

        // Burn the collateral tokens
        token.unlockTokens(loan.borrower, loan.collateralTokens);
        token.burn(loan.borrower, loan.collateralTokens);

        loan.status = LoanStatus.Canceled;

        emit CollateralClaimed(loanId, loan.borrower, loan.collateralTokens);
    }

    // ============================================================
    //                    VIEW FUNCTIONS
    // ============================================================

    /**
     * @notice Calculates interest for a loan
     * @param principal The principal amount
     * @param duration The loan duration in seconds
     * @return The interest amount
     */
    function calculateInterest(uint256 principal, uint256 duration)
        public
        view
        returns (uint256)
    {
        // Interest = Principal * Rate * (Duration / Year)
        // Rate is in basis points (500 = 5%)
        uint256 year = 365 days;
        return (principal * interestRate * duration) / (10000 * year);
    }

    /**
     * @notice Gets the max loan amount for a borrower
     * @param borrower The borrower's address
     * @return The maximum loan amount
     */
    function getMaxLoanAmount(address borrower) external view returns (uint256) {
        uint256 contribution = vault.getMemberBalance(borrower);
        uint256 borrowerMaxLTV = _calculateMaxLTV(borrower);
        return (contribution * borrowerMaxLTV) / 10000;
    }

    /**
     * @notice Gets required collateral for a loan amount
     * @param amount The loan amount
     * @return The required collateral in LAK tokens
     */
    function getRequiredCollateral(uint256 amount) external view returns (uint256) {
        uint256 collateralNeeded = (amount * collateralRatio) / 10000;
        return collateralNeeded * 10**12; // Convert to 18 decimals
    }

    /**
     * @notice Gets all loans for a borrower
     * @param borrower The borrower's address
     * @return loanIds Array of loan IDs
     */
    function getBorrowerLoans(address borrower)
        external
        view
        returns (uint256[] memory)
    {
        return borrowerLoans[borrower];
    }

    /**
     * @notice Gets loan details
     * @param loanId The loan ID
     */
    function getLoan(uint256 loanId)
        external
        view
        returns (
            uint256 id,
            address borrower,
            uint256 principal,
            uint256 interest,
            uint256 collateralTokens,
            uint256 startTime,
            uint256 dueTime,
            uint256 repaidAmount,
            uint256 totalOwed,
            uint256 remaining,
            LoanStatus status,
            string memory reason
        )
    {
        Loan storage loan = loans[loanId];
        uint256 owed = loan.principal + loan.interest;
        return (
            loan.id,
            loan.borrower,
            loan.principal,
            loan.interest,
            loan.collateralTokens,
            loan.startTime,
            loan.dueTime,
            loan.repaidAmount,
            owed,
            owed - loan.repaidAmount,
            loan.status,
            loan.reason
        );
    }

    // ============================================================
    //              INTERNAL HELPERS
    // ============================================================

    /**
     * @notice Calculates the max LTV for a borrower based on their contribution tier
     * @param borrower The borrower's address
     * @return The LTV in basis points
     */
    function _calculateMaxLTV(address borrower) internal view returns (uint256) {
        uint8 tier = vault.getContributionTier(borrower);
        if (tier == 3) return TIER3_LTV;
        if (tier == 2) return TIER2_LTV;
        return TIER1_LTV;
    }

    // ============================================================
    //                  ADMIN FUNCTIONS
    // ============================================================

    /**
     * @notice Sets the interest rate
     * @param newRate The new rate in basis points
     */
    function setInterestRate(uint256 newRate)
        external
        onlyRole(DEFAULT_ADMIN_ROLE)
    {
        uint256 oldRate = interestRate;
        interestRate = newRate;
        emit InterestRateUpdated(oldRate, newRate);
    }

    /**
     * @notice Sets the max LTV ratio
     * @param newLTV The new ratio in basis points
     */
    function setMaxLTV(uint256 newLTV) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newLTV <= 10000, "Invalid LTV");
        uint256 oldLTV = maxLTV;
        maxLTV = newLTV;
        emit MaxLTVUpdated(oldLTV, newLTV);
    }

    /**
     * @notice Sets the collateral ratio
     * @param newRatio The new ratio in basis points
     */
    function setCollateralRatio(uint256 newRatio)
        external
        onlyRole(DEFAULT_ADMIN_ROLE)
    {
        uint256 oldRatio = collateralRatio;
        collateralRatio = newRatio;
        emit CollateralRatioUpdated(oldRatio, newRatio);
    }

    /**
     * @notice Sets the auto-approval threshold
     * @param newThreshold The new threshold
     */
    function setAutoApproveThreshold(uint256 newThreshold)
        external
        onlyRole(DEFAULT_ADMIN_ROLE)
    {
        uint256 oldThreshold = autoApproveThreshold;
        autoApproveThreshold = newThreshold;
        emit ThresholdUpdated(oldThreshold, newThreshold);
    }

    /**
     * @notice Pause loans
     */
    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    /**
     * @notice Unpause loans
     */
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }
}

contracts/LakomiToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title LakomiToken
 * @author Lakomi Protocol
 * @notice Membership token for the Lakomi community platform
 * @dev ERC-20 token with membership registry, collateral locking, and access control
 *
 * Key Features:
 * - 1 registered member = 1 vote (equal governance)
 * - Tokens can be locked as loan collateral
 * - Minted when members join, burned when they exit
 * - Role-based access control for minting/burning/locking
 * - Membership registry for 1-member-1-vote governance
 */
contract LakomiToken is ERC20, AccessControl, ReentrancyGuard {

    // ============================================================
    //                        ROLES
    // ============================================================

    /// @dev Role for minting tokens (admin or governance)
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");

    /// @dev Role for burning tokens (when members exit)
    bytes32 public constant BURNER_ROLE = keccak256("BURNER_ROLE");

    /// @dev Role for locking/unlocking tokens (LakomiLoans contract)
    bytes32 public constant LOCKER_ROLE = keccak256("LOCKER_ROLE");

    /// @dev Role for managing membership (admin or governance)
    bytes32 public constant MEMBERSHIP_ROLE = keccak256("MEMBERSHIP_ROLE");

    // ============================================================
    //                      STATE VARIABLES
    // ============================================================

    /// @dev Maximum supply cap
    uint256 public constant MAX_SUPPLY = 1_000_000 * 10**18;

    /// @dev Tokens locked as collateral for loans
    mapping(address => uint256) private _lockedBalances;

    /// @dev Whether token transfers are enabled
    bool public transfersEnabled;

    /// @dev LakomiVault contract address
    address public lakomiVault;

    /// @dev LakomiGovern contract address
    address public lakomiGovern;

    /// @dev LakomiLoans contract address
    address public lakomiLoans;

    /// @dev Default tokens minted to new members
    uint256 public constant DEFAULT_MINT_AMOUNT = 100 * 10**18;

    // ============================================================
    //                  MEMBERSHIP REGISTRY
    // ============================================================

    /// @dev Tracks registered members for 1-member-1-vote governance
    mapping(address => bool) public isRegisteredMember;

    /// @dev Total count of registered members (for quorum calculation)
    uint256 public memberCount;

    // ============================================================
    //                        EVENTS
    // ============================================================

    event TokensMinted(address indexed to, uint256 amount, uint256 timestamp);
    event TokensBurned(address indexed from, uint256 amount, uint256 timestamp);
    event TokensLocked(address indexed account, uint256 amount, uint256 timestamp);
    event TokensUnlocked(address indexed account, uint256 amount, uint256 timestamp);
    event TransfersToggled(bool enabled, address indexed by);
    event VaultSet(address indexed vault);
    event GovernSet(address indexed govern);
    event LoansSet(address indexed loans);
    event MemberRegistered(address indexed member, uint256 timestamp);
    event MembershipRevoked(address indexed member, uint256 timestamp);

    // ============================================================
    //                        ERRORS
    // ============================================================

    error LakomiToken__ZeroAddress();
    error LakomiToken__InsufficientBalance();
    error LakomiToken__ExceedsMaxSupply();
    error LakomiToken__TransfersDisabled();
    error LakomiToken__InsufficientUnlockedTokens();
    error LakomiToken__NothingToUnlock();
    error LakomiToken__AlreadySet();

    // ============================================================
    //                      CONSTRUCTOR
    // ============================================================

    /**
     * @dev Grants DEFAULT_ADMIN_ROLE to deployer
     */
    constructor() ERC20("Lakomi Token", "LAK") {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(MINTER_ROLE, msg.sender);
        _grantRole(BURNER_ROLE, msg.sender);
        transfersEnabled = true;
    }

    // ============================================================
    //                    CORE FUNCTIONS
    // ============================================================

    /**
     * @notice Mints governance tokens to a new member
     * @dev Only callable by MINTER_ROLE
     * @param to The recipient address
     * @param amount The amount to mint
     */
    function mint(address to, uint256 amount)
        external
        onlyRole(MINTER_ROLE)
        nonReentrant
    {
        if (to == address(0)) revert LakomiToken__ZeroAddress();
        if (totalSupply() + amount > MAX_SUPPLY) revert LakomiToken__ExceedsMaxSupply();

        _mint(to, amount);
        emit TokensMinted(to, amount, block.timestamp);
    }

    /**
     * @notice Mints default tokens to a new member
     * @dev Convenience function for standard membership
     * @param to The recipient address
     */
    function mintDefault(address to)
        external
        onlyRole(MINTER_ROLE)
        nonReentrant
    {
        if (to == address(0)) revert LakomiToken__ZeroAddress();
        if (totalSupply() + DEFAULT_MINT_AMOUNT > MAX_SUPPLY)
            revert LakomiToken__ExceedsMaxSupply();

        _mint(to, DEFAULT_MINT_AMOUNT);
        emit TokensMinted(to, DEFAULT_MINT_AMOUNT, block.timestamp);
    }

    /**
     * @notice Burns tokens when a member exits
     * @dev Only callable by BURNER_ROLE
     * @param from The address to burn from
     * @param amount The amount to burn
     */
    function burn(address from, uint256 amount)
        external
        onlyRole(BURNER_ROLE)
        nonReentrant
    {
        if (from == address(0)) revert LakomiToken__ZeroAddress();
        if (balanceOf(from) < amount) revert LakomiToken__InsufficientBalance();

        _burn(from, amount);
        emit TokensBurned(from, amount, block.timestamp);
    }

    /**
     * @notice Locks tokens as collateral for a loan
     * @dev Only callable by LOCKER_ROLE (LakomiLoans)
     * @param account The address to lock tokens from
     * @param amount The amount to lock
     */
    function lockTokens(address account, uint256 amount)
        external
        onlyRole(LOCKER_ROLE)
        nonReentrant
    {
        if (account == address(0)) revert LakomiToken__ZeroAddress();
        if (balanceOf(account) - _lockedBalances[account] < amount)
            revert LakomiToken__InsufficientUnlockedTokens();

        _lockedBalances[account] += amount;
        emit TokensLocked(account, amount, block.timestamp);
    }

    /**
     * @notice Unlocks tokens after loan repayment
     * @dev Only callable by LOCKER_ROLE (LakomiLoans)
     * @param account The address to unlock tokens for
     * @param amount The amount to unlock
     */
    function unlockTokens(address account, uint256 amount)
        external
        onlyRole(LOCKER_ROLE)
        nonReentrant
    {
        if (account == address(0)) revert LakomiToken__ZeroAddress();
        if (_lockedBalances[account] < amount) revert LakomiToken__NothingToUnlock();

        _lockedBalances[account] -= amount;
        emit TokensUnlocked(account, amount, block.timestamp);
    }

    // ============================================================
    //                    VIEW FUNCTIONS
    // ============================================================

    /**
     * @notice Gets the locked token balance for an account
     * @param account The address to query
     * @return The locked token amount
     */
    function getLockedBalance(address account) external view returns (uint256) {
        return _lockedBalances[account];
    }

    /**
     * @notice Gets the available (unlocked) balance for voting/transfer
     * @param account The address to query
     * @return The available balance
     */
    function getAvailableBalance(address account) external view returns (uint256) {
        return balanceOf(account) - _lockedBalances[account];
    }

    /**
     * @notice Gets voting power — 1 if registered member, 0 if not
     * @param account The address to query
     * @return 1 for registered members, 0 otherwise
     */
    function getVotingPower(address account) external view returns (uint256) {
        return isRegisteredMember[account] ? 1 : 0;
    }

    // ============================================================
    //                  MEMBERSHIP FUNCTIONS
    // ============================================================

    /**
     * @notice Self-registration for open membership (UU 25/1992 Pasal 5(1))
     * @dev Any address can register themselves. Mints default governance tokens.
     *      Simpanan Pokok payment to LakomiVault is handled separately.
     */
    function registerMember()
        external
        nonReentrant
    {
        if (msg.sender == address(0)) revert LakomiToken__ZeroAddress();
        require(!isRegisteredMember[msg.sender], "Already registered");

        isRegisteredMember[msg.sender] = true;
        memberCount++;

        if (totalSupply() + DEFAULT_MINT_AMOUNT <= MAX_SUPPLY) {
            _mint(msg.sender, DEFAULT_MINT_AMOUNT);
            emit TokensMinted(msg.sender, DEFAULT_MINT_AMOUNT, block.timestamp);
        }

        emit MemberRegistered(msg.sender, block.timestamp);
    }

    /**
     * @notice Admin-assisted registration (for members without wallet access)
     * @dev Only callable by MEMBERSHIP_ROLE. Also mints default tokens.
     * @param member The address to register
     */
    function registerMemberAdmin(address member)
        external
        onlyRole(MEMBERSHIP_ROLE)
        nonReentrant
    {
        if (member == address(0)) revert LakomiToken__ZeroAddress();
        require(!isRegisteredMember[member], "Already registered");

        isRegisteredMember[member] = true;
        memberCount++;

        if (totalSupply() + DEFAULT_MINT_AMOUNT <= MAX_SUPPLY) {
            _mint(member, DEFAULT_MINT_AMOUNT);
            emit TokensMinted(member, DEFAULT_MINT_AMOUNT, block.timestamp);
        }

        emit MemberRegistered(member, block.timestamp);
    }

    /**
     * @notice Revokes membership — only via governance (UU 25/1992 Pasal 27)
     * @dev Callable by MEMBERSHIP_ROLE (governance) or DEFAULT_ADMIN_ROLE
     * @param member The address to revoke
     */
    function revokeMembership(address member)
        external
        nonReentrant
    {
        if (member == address(0)) revert LakomiToken__ZeroAddress();
        require(isRegisteredMember[member], "Not a member");
        require(
            hasRole(MEMBERSHIP_ROLE, msg.sender) || hasRole(DEFAULT_ADMIN_ROLE, msg.sender),
            "Not authorized"
        );

        isRegisteredMember[member] = false;
        memberCount--;

        uint256 balance = balanceOf(member);
        if (balance > 0) {
            _burn(member, balance);
            emit TokensBurned(member, balance, block.timestamp);
        }

        emit MembershipRevoked(member, block.timestamp);
    }

    /**
     * @notice Returns the total number of registered members
     * @return The member count
     */
    function getMemberCount() external view returns (uint256) {
        return memberCount;
    }

    // ============================================================
    //                  ADMIN FUNCTIONS
    // ============================================================

    /**
     * @notice Enables or disables token transfers
     * @dev Only callable by DEFAULT_ADMIN_ROLE
     * @param enabled The new transfer state
     */
    function setTransfersEnabled(bool enabled)
        external
        onlyRole(DEFAULT_ADMIN_ROLE)
    {
        transfersEnabled = enabled;
        emit TransfersToggled(enabled, msg.sender);
    }

    /**
     * @notice Sets the LakomiVault contract address
     * @dev Only callable by DEFAULT_ADMIN_ROLE
     * @param vault The vault address
     */
    function setLakomiVault(address vault)
        external
        onlyRole(DEFAULT_ADMIN_ROLE)
    {
        if (vault == address(0)) revert LakomiToken__ZeroAddress();
        if (lakomiVault != address(0)) revert LakomiToken__AlreadySet();
        lakomiVault = vault;
        emit VaultSet(vault);
    }

    /**
     * @notice Sets the LakomiGovern contract address
     * @dev Only callable by DEFAULT_ADMIN_ROLE
     * @param govern The governance address
     */
    function setLakomiGovern(address govern)
        external
        onlyRole(DEFAULT_ADMIN_ROLE)
    {
        if (govern == address(0)) revert LakomiToken__ZeroAddress();
        if (lakomiGovern != address(0)) revert LakomiToken__AlreadySet();
        lakomiGovern = govern;
        emit GovernSet(govern);
    }

    /**
     * @notice Sets the LakomiLoans contract address
     * @dev Only callable by DEFAULT_ADMIN_ROLE
     * @param loans The loans contract address
     */
    function setLakomiLoans(address loans)
        external
        onlyRole(DEFAULT_ADMIN_ROLE)
    {
        if (loans == address(0)) revert LakomiToken__ZeroAddress();
        if (lakomiLoans != address(0)) revert LakomiToken__AlreadySet();
        lakomiLoans = loans;
        emit LoansSet(loans);
    }

    // ============================================================
    //                    OVERRIDES
    // ============================================================

    /**
     * @dev Override to check transfers are enabled
     */
    function _update(address from, address to, uint256 value)
        internal
        override
    {
        super._update(from, to, value);

        // Allow minting (from == 0) and burning (to == 0) regardless
        if (from != address(0) && to != address(0)) {
            if (!transfersEnabled) revert LakomiToken__TransfersDisabled();
        }
    }

    /**
     * @dev Override transfer to check unlocked balance
     */
    function transfer(address to, uint256 value)
        public
        override
        returns (bool)
    {
        if (balanceOf(msg.sender) - _lockedBalances[msg.sender] < value)
            revert LakomiToken__InsufficientUnlockedTokens();
        return super.transfer(to, value);
    }

    /**
     * @dev Override transferFrom to check unlocked balance
     */
    function transferFrom(address from, address to, uint256 value)
        public
        override
        returns (bool)
    {
        if (balanceOf(from) - _lockedBalances[from] < value)
            revert LakomiToken__InsufficientUnlockedTokens();
        return super.transferFrom(from, to, value);
    }
}

contracts/LakomiVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/**
 * @title LakomiVault
 * @author Lakomi Protocol
 * @notice Treasury management for the Lakomi cooperative (koperasi)
 * @dev UU 25/1992 compliant: Simpanan Pokok, Simpanan Wajib, Simpanan Sukarela, SHU distribution
 *
 * Compliance (UU 25/1992):
 * - Pasal 22(2): Simpanan Pokok (one-time on join) + Simpanan Wajib (periodic mandatory)
 * - Pasal 41: Three types of simpanan (Pokok, Wajib, Sukarela)
 * - Pasal 45: SHU (Sisa Hasil Usaha) = Revenue - Costs, distributed by contribution
 */
contract LakomiVault is AccessControl, ReentrancyGuard, Pausable {

    using SafeERC20 for IERC20;

    // ============================================================
    //                        ROLES
    // ============================================================

    bytes32 public constant TREASURER_ROLE = keccak256("TREASURER_ROLE");
    bytes32 public constant GOVERN_ROLE = keccak256("GOVERN_ROLE");
    bytes32 public constant LOAN_ROLE = keccak256("LOAN_ROLE");

    // ============================================================
    //                      STATE VARIABLES
    // ============================================================

    IERC20 public immutable stableToken;

    uint256 public totalDeposited;
    uint256 public totalWithdrawn;

    mapping(address => uint256) public contributions;
    uint256 public totalShares;
    mapping(address => uint256) public shares;

    uint256 public withdrawalThreshold;
    uint256 public withdrawalTimelock;

    struct PendingWithdrawal {
        address recipient;
        uint256 amount;
        uint256 timestamp;
        uint256 executableAt;
        bool executed;
        bool approved;
    }

    mapping(uint256 => PendingWithdrawal) public pendingWithdrawals;
    uint256 public nextWithdrawalId;

    address public lakomiToken;
    address public lakomiGovern;

    // ============================================================
    //              SIMPANAN (UU 25/1992 Pasal 41)
    // ============================================================

    uint256 public simpananPokokAmount;
    uint256 public simpananWajibAmount;
    uint256 public simpananWajibPeriod;
    uint256 public constant TIER2_THRESHOLD = 500 * 10**6;
    uint256 public constant TIER3_THRESHOLD = 2000 * 10**6;

    mapping(address => uint256) public simpananPokok;
    mapping(address => uint256) public simpananWajibTotal;
    mapping(address => uint256) public simpananWajibLastPaid;
    mapping(address => uint256) public simpananWajibPeriodsPaid;
    mapping(address => uint256) public firstDepositTime;

    // ============================================================
    //              SHU (UU 25/1992 Pasal 45)
    // ============================================================

    uint256 public accumulatedRevenue;
    uint256 public totalSHUDistributed;
    uint256 public shuDistributionPeriod;
    uint256 public lastSHUDistribution;
    uint256 public operationalReserveBps;

    struct SHUDistribution {
        uint256 totalAmount;
        uint256 memberCount;
        uint256 timestamp;
        uint256 perShare;
    }

    mapping(uint256 => SHUDistribution) public shuDistributions;
    uint256 public shuDistributionCount;

    mapping(address => uint256) public shuClaimed;
    mapping(address => uint256) public shuPending;

    mapping(uint256 => mapping(address => bool)) public shuClaimedForDistribution;

    // ============================================================
    //                        EVENTS
    // ============================================================

    event Deposited(address indexed member, uint256 amount, uint256 shares, uint256 timestamp);
    event Withdrawn(address indexed member, uint256 amount, uint256 shares, uint256 timestamp);
    event WithdrawalRequested(uint256 indexed id, address indexed recipient, uint256 amount, uint256 executableAt);
    event WithdrawalExecuted(uint256 indexed id, address recipient, uint256 amount);
    event WithdrawalCanceled(uint256 indexed id);
    event GovernanceSpend(address indexed to, uint256 amount, bytes reason);
    event ThresholdUpdated(uint256 oldThreshold, uint256 newThreshold);
    event TimelockUpdated(uint256 oldTimelock, uint256 newTimelock);
    event TokenSet(address indexed token);
    event GovernSet(address indexed govern);
    event ContributionTierUpdated(address indexed member, uint8 tier);

    event SimpananPokokPaid(address indexed member, uint256 amount, uint256 timestamp);
    event SimpananWajibPaid(address indexed member, uint256 amount, uint256 periods, uint256 timestamp);
    event SimpananPokokAmountUpdated(uint256 oldAmount, uint256 newAmount);
    event SimpananWajibAmountUpdated(uint256 oldAmount, uint256 newAmount);

    event RevenueReceived(uint256 amount, uint256 timestamp);
    event SHUDistributed(uint256 indexed distributionId, uint256 totalAmount, uint256 memberCount, uint256 perShare);
    event SHUClaimed(address indexed member, uint256 indexed distributionId, uint256 amount);

    // ============================================================
    //                        ERRORS
    // ============================================================

    error LakomiVault__ZeroAddress();
    error LakomiVault__ZeroAmount();
    error LakomiVault__InsufficientBalance();
    error LakomiVault__InsufficientShares();
    error LakomiVault__ExceedsThreshold();
    error LakomiVault__TimelockNotMet();
    error LakomiVault__AlreadyExecuted();
    error LakomiVault__NotApproved();
    error LakomiVault__InvalidWithdrawal();
    error LakomiVault__AlreadySet();
    error LakomiVault__TransferFailed();
    error LakomiVault__NotMember();
    error LakomiVault__SimpananPokokNotPaid();
    error LakomiVault__SimpananPokokAlreadyPaid();
    error LakomiVault__SimpananWajibNotDue();
    error LakomiVault__NoSHUToClaim();
    error LakomiVault__NoRevenueToDistribute();

    // ============================================================
    //                      CONSTRUCTOR
    // ============================================================

    constructor(
        address _stableToken,
        uint256 _withdrawalThreshold,
        uint256 _withdrawalTimelock,
        uint256 _simpananPokokAmount,
        uint256 _simpananWajibAmount,
        uint256 _simpananWajibPeriod
    ) {
        if (_stableToken == address(0)) revert LakomiVault__ZeroAddress();

        stableToken = IERC20(_stableToken);
        withdrawalThreshold = _withdrawalThreshold;
        withdrawalTimelock = _withdrawalTimelock;

        simpananPokokAmount = _simpananPokokAmount;
        simpananWajibAmount = _simpananWajibAmount;
        simpananWajibPeriod = _simpananWajibPeriod;

        operationalReserveBps = 1000; // 10% reserve
        shuDistributionPeriod = 365 days;

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(TREASURER_ROLE, msg.sender);
    }

    // ============================================================
    //               SIMPANAN POKOK (UU 25/1992 Pasal 41(1))
    // ============================================================

    function paySimpananPokok(address member) external nonReentrant {
        if (simpananPokok[member] > 0) revert LakomiVault__SimpananPokokAlreadyPaid();

        stableToken.safeTransferFrom(member, address(this), simpananPokokAmount);

        simpananPokok[member] = simpananPokokAmount;
        contributions[member] += simpananPokokAmount;
        totalDeposited += simpananPokokAmount;

        if (firstDepositTime[member] == 0) {
            firstDepositTime[member] = block.timestamp;
        }

        emit SimpananPokokPaid(member, simpananPokokAmount, block.timestamp);
    }

    function hasPaidSimpananPokok(address member) external view returns (bool) {
        return simpananPokok[member] > 0;
    }

    // ============================================================
    //               SIMPANAN WAJIB (UU 25/1992 Pasal 41(2))
    // ============================================================

    function paySimpananWajib() external nonReentrant whenNotPaused {
        if (simpananPokok[msg.sender] == 0) revert LakomiVault__SimpananPokokNotPaid();

        stableToken.safeTransferFrom(msg.sender, address(this), simpananWajibAmount);

        simpananWajibTotal[msg.sender] += simpananWajibAmount;
        simpananWajibPeriodsPaid[msg.sender]++;
        simpananWajibLastPaid[msg.sender] = block.timestamp;
        contributions[msg.sender] += simpananWajibAmount;
        totalDeposited += simpananWajibAmount;

        emit SimpananWajibPaid(msg.sender, simpananWajibAmount, simpananWajibPeriodsPaid[msg.sender], block.timestamp);
    }

    function getSimpananWajibPeriodsOwed(address member) external view returns (uint256) {
        if (simpananPokok[member] == 0) return 0;
        if (firstDepositTime[member] == 0) return 0;

        uint256 elapsed = block.timestamp - firstDepositTime[member];
        uint256 periodsElapsed = elapsed / simpananWajibPeriod;
        if (periodsElapsed > simpananWajibPeriodsPaid[member]) {
            return periodsElapsed - simpananWajibPeriodsPaid[member];
        }
        return 0;
    }

    function isSimpananWajibCurrent(address member) external view returns (bool) {
        uint256 owed = this.getSimpananWajibPeriodsOwed(member);
        return owed == 0;
    }

    // ============================================================
    //            SIMPANAN SUKARELA (UU 25/1992 Pasal 41(3))
    // ============================================================

    function deposit(uint256 amount)
        external
        whenNotPaused
        nonReentrant
        returns (uint256 sharesIssued)
    {
        if (amount == 0) revert LakomiVault__ZeroAmount();
        if (simpananPokok[msg.sender] == 0) revert LakomiVault__SimpananPokokNotPaid();

        uint256 totalAssets = getTotalAssets();
        if (totalShares == 0) {
            sharesIssued = amount;
        } else {
            sharesIssued = (amount * totalShares) / totalAssets;
        }

        stableToken.safeTransferFrom(msg.sender, address(this), amount);

        contributions[msg.sender] += amount;
        shares[msg.sender] += sharesIssued;
        totalShares += sharesIssued;
        totalDeposited += amount;

        if (firstDepositTime[msg.sender] == 0) {
            firstDepositTime[msg.sender] = block.timestamp;
        }

        emit Deposited(msg.sender, amount, sharesIssued, block.timestamp);
    }

    function withdraw(uint256 amount)
        external
        whenNotPaused
        nonReentrant
        returns (uint256 actualAmount)
    {
        if (amount == 0) revert LakomiVault__ZeroAmount();
        if (amount >= withdrawalThreshold) revert LakomiVault__ExceedsThreshold();
        if (contributions[msg.sender] < amount) revert LakomiVault__InsufficientBalance();

        uint256 sukarela = contributions[msg.sender] - simpananPokok[msg.sender] - simpananWajibTotal[msg.sender];
        if (amount > sukarela) revert LakomiVault__InsufficientBalance();

        uint256 totalAssets = getTotalAssets();
        uint256 sharesToBurn = (amount * totalShares) / totalAssets;

        if (shares[msg.sender] < sharesToBurn) revert LakomiVault__InsufficientShares();

        contributions[msg.sender] -= amount;
        shares[msg.sender] -= sharesToBurn;
        totalShares -= sharesToBurn;
        totalWithdrawn += amount;

        stableToken.safeTransfer(msg.sender, amount);

        emit Withdrawn(msg.sender, amount, sharesToBurn, block.timestamp);

        return amount;
    }

    function requestWithdrawal(address recipient, uint256 amount)
        external
        whenNotPaused
        nonReentrant
        returns (uint256 withdrawalId)
    {
        if (recipient == address(0)) revert LakomiVault__ZeroAddress();
        if (amount == 0) revert LakomiVault__ZeroAmount();
        if (amount < withdrawalThreshold) revert LakomiVault__ExceedsThreshold();

        uint256 sukarela = contributions[msg.sender] - simpananPokok[msg.sender] - simpananWajibTotal[msg.sender];
        if (sukarela < amount) revert LakomiVault__InsufficientBalance();

        uint256 executableAt = block.timestamp + withdrawalTimelock;

        withdrawalId = nextWithdrawalId++;
        pendingWithdrawals[withdrawalId] = PendingWithdrawal({
            recipient: recipient,
            amount: amount,
            timestamp: block.timestamp,
            executableAt: executableAt,
            executed: false,
            approved: false
        });

        emit WithdrawalRequested(withdrawalId, recipient, amount, executableAt);
    }

    function approveWithdrawal(uint256 withdrawalId) external onlyRole(GOVERN_ROLE) {
        PendingWithdrawal storage w = pendingWithdrawals[withdrawalId];
        if (w.recipient == address(0)) revert LakomiVault__InvalidWithdrawal();
        if (w.executed) revert LakomiVault__AlreadyExecuted();

        w.approved = true;
    }

    function executeWithdrawal(uint256 withdrawalId) external whenNotPaused nonReentrant {
        PendingWithdrawal storage w = pendingWithdrawals[withdrawalId];

        if (w.recipient == address(0)) revert LakomiVault__InvalidWithdrawal();
        if (w.executed) revert LakomiVault__AlreadyExecuted();
        if (!w.approved) revert LakomiVault__NotApproved();
        if (block.timestamp < w.executableAt) revert LakomiVault__TimelockNotMet();

        uint256 totalAssets = getTotalAssets();
        uint256 sharesToBurn = (w.amount * totalShares) / totalAssets;

        contributions[w.recipient] -= w.amount;
        shares[w.recipient] -= sharesToBurn;
        totalShares -= sharesToBurn;
        totalWithdrawn += w.amount;
        w.executed = true;

        stableToken.safeTransfer(w.recipient, w.amount);

        emit WithdrawalExecuted(withdrawalId, w.recipient, w.amount);
    }

    function cancelWithdrawal(uint256 withdrawalId) external {
        PendingWithdrawal storage w = pendingWithdrawals[withdrawalId];

        if (w.recipient == address(0)) revert LakomiVault__InvalidWithdrawal();
        if (w.executed) revert LakomiVault__AlreadyExecuted();
        if (msg.sender != w.recipient && !hasRole(DEFAULT_ADMIN_ROLE, msg.sender))
            revert LakomiVault__InvalidWithdrawal();

        w.executed = true;
        emit WithdrawalCanceled(withdrawalId);
    }

    function getPendingWithdrawal(uint256 withdrawalId)
        external
        view
        returns (
            address recipient,
            uint256 amount,
            uint256 timestamp,
            uint256 executableAt,
            bool executed,
            bool approved
        )
    {
        PendingWithdrawal storage w = pendingWithdrawals[withdrawalId];
        return (w.recipient, w.amount, w.timestamp, w.executableAt, w.executed, w.approved);
    }

    // ============================================================
    //         SHU DISTRIBUTION (UU 25/1992 Pasal 45)
    // ============================================================

    function receiveRevenue(uint256 amount) external nonReentrant {
        if (amount == 0) revert LakomiVault__ZeroAmount();

        stableToken.safeTransferFrom(msg.sender, address(this), amount);
        accumulatedRevenue += amount;

        emit RevenueReceived(amount, block.timestamp);
    }

    function distributeSHU() external onlyRole(GOVERN_ROLE) nonReentrant {
        if (accumulatedRevenue == 0) revert LakomiVault__NoRevenueToDistribute();

        uint256 reserve = (accumulatedRevenue * operationalReserveBps) / 10000;
        uint256 distributable = accumulatedRevenue - reserve;

        if (distributable == 0) revert LakomiVault__NoRevenueToDistribute();
        if (totalShares == 0) revert LakomiVault__NoRevenueToDistribute();

        uint256 perShare = distributable / totalShares;

        uint256 distId = shuDistributionCount++;
        shuDistributions[distId] = SHUDistribution({
            totalAmount: distributable,
            memberCount: 0,
            timestamp: block.timestamp,
            perShare: perShare
        });

        totalSHUDistributed += distributable;
        accumulatedRevenue = reserve;

        lastSHUDistribution = block.timestamp;

        emit SHUDistributed(distId, distributable, shuDistributions[distId].memberCount, perShare);
    }

    function claimSHU(uint256 distributionId) external nonReentrant {
        if (shuClaimedForDistribution[distributionId][msg.sender])
            revert LakomiVault__NoSHUToClaim();

        SHUDistribution storage dist = shuDistributions[distributionId];
        if (dist.totalAmount == 0) revert LakomiVault__NoSHUToClaim();

        uint256 memberShares = shares[msg.sender];
        if (memberShares == 0) revert LakomiVault__NoSHUToClaim();

        uint256 amount = memberShares * dist.perShare;
        if (amount == 0) revert LakomiVault__NoSHUToClaim();

        shuClaimedForDistribution[distributionId][msg.sender] = true;
        shuClaimed[msg.sender] += amount;

        stableToken.safeTransfer(msg.sender, amount);

        emit SHUClaimed(msg.sender, distributionId, amount);
    }

    function getPendingSHU(address member) external view returns (uint256) {
        uint256 pending = 0;
        for (uint256 i = 0; i < shuDistributionCount; i++) {
            if (!shuClaimedForDistribution[i][member] && shares[member] > 0) {
                pending += shares[member] * shuDistributions[i].perShare;
            }
        }
        return pending;
    }

    // ============================================================
    //                  GOVERNANCE SPENDING
    // ============================================================

    function governanceSpend(
        address to,
        uint256 amount,
        bytes calldata reason
    ) external onlyRole(GOVERN_ROLE) nonReentrant {
        if (to == address(0)) revert LakomiVault__ZeroAddress();
        if (amount == 0) revert LakomiVault__ZeroAmount();
        if (stableToken.balanceOf(address(this)) < amount)
            revert LakomiVault__InsufficientBalance();

        stableToken.safeTransfer(to, amount);

        emit GovernanceSpend(to, amount, reason);
    }

    // ============================================================
    //                    VIEW FUNCTIONS
    // ============================================================

    function getTotalAssets() public view returns (uint256) {
        return stableToken.balanceOf(address(this));
    }

    function getMemberBalance(address member) external view returns (uint256) {
        return contributions[member];
    }

    function getMemberSharePercent(address member) external view returns (uint256) {
        if (totalShares == 0) return 0;
        return (shares[member] * 10000) / totalShares;
    }

    function getMemberValue(address member) external view returns (uint256) {
        if (totalShares == 0) return 0;
        return (shares[member] * getTotalAssets()) / totalShares;
    }

    function contributionScore(address member) external view returns (uint256) {
        uint256 deposited = contributions[member];
        if (deposited == 0) return 0;

        uint256 depositScore = deposited / 10**6;

        uint256 duration = 0;
        if (firstDepositTime[member] > 0) {
            duration = (block.timestamp - firstDepositTime[member]) / 30 days;
        }

        return depositScore + (duration * 10);
    }

    function getContributionTier(address member) external view returns (uint8) {
        uint256 deposited = contributions[member];
        if (deposited >= TIER3_THRESHOLD) return 3;
        if (deposited >= TIER2_THRESHOLD) return 2;
        return 1;
    }

    function getSimpananSummary(address member) external view returns (
        uint256 pokok,
        uint256 wajibTotal,
        uint256 wajibPeriodsPaid,
        uint256 wajibPeriodsOwed,
        uint256 sukarela,
        uint256 totalContribution
    ) {
        pokok = simpananPokok[member];
        wajibTotal = simpananWajibTotal[member];
        wajibPeriodsPaid = simpananWajibPeriodsPaid[member];
        wajibPeriodsOwed = this.getSimpananWajibPeriodsOwed(member);
        totalContribution = contributions[member];
        sukarela = totalContribution - pokok - wajibTotal;
    }

    // ============================================================
    //                  ADMIN FUNCTIONS
    // ============================================================

    function setWithdrawalThreshold(uint256 newThreshold) external onlyRole(DEFAULT_ADMIN_ROLE) {
        uint256 oldThreshold = withdrawalThreshold;
        withdrawalThreshold = newThreshold;
        emit ThresholdUpdated(oldThreshold, newThreshold);
    }

    function setWithdrawalTimelock(uint256 newTimelock) external onlyRole(DEFAULT_ADMIN_ROLE) {
        uint256 oldTimelock = withdrawalTimelock;
        withdrawalTimelock = newTimelock;
        emit TimelockUpdated(oldTimelock, newTimelock);
    }

    function setLakomiToken(address token) external onlyRole(DEFAULT_ADMIN_ROLE) {
        if (token == address(0)) revert LakomiVault__ZeroAddress();
        if (lakomiToken != address(0)) revert LakomiVault__AlreadySet();
        lakomiToken = token;
        emit TokenSet(token);
    }

    function setLakomiGovern(address govern) external onlyRole(DEFAULT_ADMIN_ROLE) {
        if (govern == address(0)) revert LakomiVault__ZeroAddress();
        if (lakomiGovern != address(0)) revert LakomiVault__AlreadySet();
        lakomiGovern = govern;
        emit GovernSet(govern);
    }

    function setSimpananPokokAmount(uint256 newAmount) external onlyRole(GOVERN_ROLE) {
        uint256 old = simpananPokokAmount;
        simpananPokokAmount = newAmount;
        emit SimpananPokokAmountUpdated(old, newAmount);
    }

    function setSimpananWajibAmount(uint256 newAmount) external onlyRole(GOVERN_ROLE) {
        uint256 old = simpananWajibAmount;
        simpananWajibAmount = newAmount;
        emit SimpananWajibAmountUpdated(old, newAmount);
    }

    function setOperationalReserveBps(uint256 newBps) external onlyRole(GOVERN_ROLE) {
        require(newBps <= 5000, "Max 50% reserve");
        operationalReserveBps = newBps;
    }

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }

    function emergencyWithdraw(
        address token,
        address to,
        uint256 amount
    ) external onlyRole(DEFAULT_ADMIN_ROLE) nonReentrant {
        IERC20(token).safeTransfer(to, amount);
    }

    function approveUSDCSpending(address spender, uint256 amount) external onlyRole(DEFAULT_ADMIN_ROLE) {
        stableToken.forceApprove(spender, amount);
    }
}

